// /frontend/src/components/WeatherApp.jsx
import React, { useEffect, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

// Fallback if nothing is stored yet (use your own default if you prefer)
const ATL = { name: "Atlanta, GA, USA", lat: 33.7490, lon: -84.3880 };

// Helpers
function isFiniteNum(n) { return typeof n === "number" && isFinite(n); }

// Backend base URL
const API_BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

export default function WeatherApp() {
  // Selected place comes from SearchSection onSelect
  const [place, setPlace] = useState(ATL);

  // Backend data
  const [weather, setWeather] = useState({
    current: null,
    hourly: [],
    daily: [],
    summary: "",
  });
  const [wLoading, setWLoading] = useState(false);
  const [wError, setWError] = useState("");

  // Fired by SearchSection when user picks a city
  function handleSearchSelect(p) {
    // p: {name, lat, lon}
    setPlace({
      name: p?.name || ATL.name,
      lat: isFiniteNum(p?.lat) ? p.lat : ATL.lat,
      lon: isFiniteNum(p?.lon) ? p.lon : ATL.lon,
    });
  }

  // Fetch backend whenever the selected place changes
  useEffect(() => {
    let abort = false;

    async function run() {
      try {
        setWLoading(true);
        setWError("");

        // Send BOTH coords and a location string to be flexible with your backend
        const res = await fetch(`${API_BASE}/api/weather/current`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            lat: place.lat,
            lon: place.lon,
            location: place.name, // if your backend expects "Atlanta,US", you can pre-format here
          }),
        });

        if (!res.ok) {
          const text = await res.text().catch(() => "");
          throw new Error(`HTTP ${res.status} ${text || res.statusText}`);
        }

        const data = await res.json();
        const normalized = {
          current: data.current ?? data?.weather?.current ?? null,
          hourly: data.hourly ?? data?.weather?.hourly ?? [],
          daily: data.daily ?? data?.weather?.daily ?? [],
          summary: data.summary ?? data?.summary ?? "",
        };

        if (!abort) setWeather(normalized);
      } catch (e) {
        if (!abort) setWError(e.message || "Failed to load weather");
      } finally {
        if (!abort) setWLoading(false);
      }
    }

    if (isFiniteNum(place.lat) && isFiniteNum(place.lon)) run();
    return () => { abort = true; };
  }, [place.lat, place.lon, place.name]);

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-hidden">
      {/* Dynamic background overlays */}
      <WeatherOverlay />

      {/* Top search */}
      <header className="px-4 pt-4">
        <SearchSection
          defaultValue={place?.name || ""}
          onSelect={handleSearchSelect}
        />
      </header>

      {/* Optional: tiny status line (remove if you don’t want it) */}
      {wLoading && (
        <div className="px-4 mt-2 text-xs text-gray-600">Loading weather…</div>
      )}
      {!wLoading && wError && (
        <div className="px-4 mt-2 text-xs text-red-600">{wError}</div>
      )}

      {/* Current city label (your existing UI can live here) */}
      <section className="px-4 mt-3 mb-2">
        <div className="text-sm text-gray-700">
          <span className="font-medium text-gray-900">{place?.name}</span>
        </div>
      </section>

      {/* Radar centered on the selected city */}
      <section className="px-4 mb-24">
        <Radar
          center={[place?.lat ?? ATL.lat, place?.lon ?? ATL.lon]}
          zoom={6}
          height={320}
          className="rounded-2xl overflow-hidden"
        />
      </section>

      {/* Forecast — if your component needs props, pass them here */}
      {/* Leave as-is if your Forecast pulls from context or elsewhere */}
      <Forecast
        // current={weather.current}
        // hourly={weather.hourly}
        // daily={weather.daily}
        // summary={weather.summary}
      />

      {/* Bottom bar */}
      <BottomBar />
    </div>
  );
}
